import hou
panel = None
# Try to find an existing panel with the HoudiniMind interface active
for t in hou.ui.curDesktop().paneTabs():
    if t.type() == hou.paneTabType.PythonPanel:
        itf = t.activeInterface()
        if itf and itf.name() == "HoudiniMind":
            panel = t
            panel.setIsCurrentTab()
            break

if not panel:
    # Try to find any available Python Panel and set its interface to HoudiniMind
    mind_itf = hou.pypanel.interfaceByName("HoudiniMind")
    if mind_itf:
        for t in hou.ui.curDesktop().paneTabs():
            if t.type() == hou.paneTabType.PythonPanel:
                t.setActiveInterface(mind_itf)
                panel = t
                panel.setIsCurrentTab()
                break

if not panel:
    hou.ui.displayMessage("Please open the 'Houdini Agent' Python Panel first from the 'Panes' menu.")

import hou
panel = None
for t in hou.ui.curDesktop().paneTabs():
    if t.type() == hou.paneTabType.PythonPanel:
        itf = t.activeInterface()
        if itf and itf.name() == "HoudiniMind":
            panel = t
            break

if panel:
    widget = panel.activeInterfaceRootWidget()
    if widget and hasattr(widget, "_dispatch_research"):
        widget._dispatch_research("Find and fix all errors in my current scene.")
else:
    hou.ui.displayMessage("Open the Houdini Agent panel to use this feature.")

